input.command:
agent-browser eval "
  (function() {
    const acceptedAnswer = document.querySelector('.accepted-answer');
    if (!acceptedAnswer) return { error: 'No accepted answer found' };

    const votes = acceptedAnswer.querySelector('.js-vote-count').innerText;
    const author = acceptedAnswer.querySelector('.user-details a').innerText;
    const codeBlocks = acceptedAnswer.querySelectorAll('pre code').length;

    const answersHeader = document.querySelector('#answers-header h2');
    const totalAnswers = answersHeader ? answersHeader.getAttribute('data-answercount') || answersHeader.innerText : 'unknown';

    return { votes, author, codeBlocks, totalAnswers };
  })()
" --json
